1	// Static tests asserting the wizard UAT transcript structure — no VM required.
2	//
3	// Transcripts may carry any of these valid STATUS values:
4	//   STATUS: ok                    (full VM run succeeded)
5	//   STATUS: pending VM run        (placeholder until VM run is executed in S06)
6	//   STATUS: failed:scenario-A     (Scenario A — fresh install — failed)
7	//   STATUS: failed:scenario-B     (Scenario B — model pre-placed — failed)
8	//   STATUS: failed:scenario-C     (Scenario C — relaunch skips wizard — failed)
9	//   STATUS: failed:scenario-D     (Scenario D — --skip-wizard flag — failed)
10	// All are accepted here; only structural completeness is enforced.
11	
12	use std::fs;
13	use std::path::Path;
14	
15	fn project_root() -> std::path::PathBuf {
16	    Path::new(env!("CARGO_MANIFEST_DIR")).to_path_buf()
17	}
18	
19	fn read_file(rel: &str) -> String {
20	    let path = project_root().join(rel);
21	    fs::read_to_string(&path).unwrap_or_else(|e| panic!("cannot read {rel}: {e}"))
22	}
23	
24	const REQUIRED_FIELDS: &[&str] = &[
25	    "STATUS:",
26	    "DISTRO:",
27	    "KERNEL:",
28	    "BINARY:",
29	    "BINARY_VERSION:",
30	    "SCENARIO_A:",
31	    "SCENARIO_B:",
32	    "SCENARIO_C:",
33	    "SCENARIO_D:",
34	    "STRATAGEM_FIRED:",
35	];
36	
37	const VALID_STATUSES: &[&str] = &[
38	    "STATUS: ok",
39	    "STATUS: pending VM run",
40	    "STATUS: failed:scenario-A",
41	    "STATUS: failed:scenario-B",
42	    "STATUS: failed:scenario-C",
43	    "STATUS: failed:scenario-D",
44	];
45	
46	fn assert_transcript(rel: &str) {
47	    let content = read_file(rel);
48	    for field in REQUIRED_FIELDS {
49	        assert!(
50	            content.contains(field),
51	            "transcript {rel} is missing required field '{field}'"
52	        );
53	    }
54	    let has_valid_status = VALID_STATUSES.iter().any(|s| content.contains(s));
55	    assert!(
56	        has_valid_status,
57	        "transcript {rel} has no recognized STATUS line; accepted values: {:?}",
58	        VALID_STATUSES
59	    );
60	}
61	
62	#[test]
63	fn debian12_wizard_transcript_has_required_fields() {
64	    assert_transcript("docs/distribution-proofs/wizard/debian12/transcript.md");
65	}
66	
67	#[test]
68	fn fedora39_wizard_transcript_has_required_fields() {
69	    assert_transcript("docs/distribution-proofs/wizard/fedora39/transcript.md");
70	}
71	
72	#[test]
73	fn arch_wizard_transcript_has_required_fields() {
74	    assert_transcript("docs/distribution-proofs/wizard/arch/transcript.md");
75	}
76	
77	#[test]
78	fn wizard_readme_contains_four_scenario_headings() {
79	    let content = read_file("docs/distribution-proofs/wizard/README.md");
80	    for scenario in &["Scenario A", "Scenario B", "Scenario C", "Scenario D"] {
81	        assert!(
82	            content.contains(scenario),
83	            "docs/distribution-proofs/wizard/README.md is missing '{scenario}' heading"
84	        );
85	    }
86	}
